import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;
import java.util.Set;
import java.util.HashSet;

class Solution {
    /**
     * @param nums The values of the nodes (0 or 1).
     * @param edges The edges of the graph.
     * @return The count of subsets satisfying the conditions.
     */
    public static long solve(long[] nums, long[][] edges) {
        int n = nums.length;
        long count = 0;

        // Adjacency list representation of the graph
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            adj.get(u).add(v);
            adj.get(v).add(u);
        }

        // Iterate through all non-empty subsets of nodes (2^n - 1 subsets)
        // A subset can be represented by a bitmask from 1 to 2^n - 1
        int totalMasks = 1 << n;

        for (int mask = 1; mask < totalMasks; mask++) {
            // 1. Calculate the sum of values for the subset s (represented by mask)
            int sum = 0;
            List<Integer> nodesInSet = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                if (((mask >> i) & 1) == 1) {
                    sum += nums[i] == 1 ? 1 : 0;
                    nodesInSet.add(i);
                }
            }

            // Check condition 2: Sum of values must be even
            if (sum % 2 != 0) {
                continue;
            }

            // 2. Check condition 1: The induced subgraph must be connected

            // If the subset has only one node, it is always connected.
            if (nodesInSet.size() == 1) {
                count++;
                continue;
            }

            // Use BFS or DFS to check connectivity within the induced subgraph
            int startNode = nodesInSet.get(0);
            Set<Integer> visited = new HashSet<>();
            Queue<Integer> queue = new LinkedList<>();

            queue.offer(startNode);
            visited.add(startNode);
            int visitedCount = 0;

            while (!queue.isEmpty()) {
                int u = queue.poll();
                visitedCount++;

                // Check neighbors of u in the original graph
                for (int v : adj.get(u)) {
                    // Only consider neighbors v that are also in the current subset (mask)
                    // And only if v has not been visited
                    if (((mask >> v) & 1) == 1 && !visited.contains(v)) {
                        visited.add(v);
                        queue.offer(v);
                    }
                }
            }

            // If the number of visited nodes equals the size of the set s, it is connected.
            if (visitedCount == nodesInSet.size()) {
                count++;
            }
        }

        return count;
    }
